frappe.web_form.after_load = () => {
    // 1. Hide the technical fields
    frappe.web_form.set_df_property('extra_details', 'hidden', 1);
    frappe.web_form.set_df_property('temp_address', 'hidden', 1);

    // 2. Capture Referral from URL (?ref=VOL-001)
    const urlParams = new URLSearchParams(window.location.search);
    const referrer = urlParams.get('ref');

    if (referrer) {
        // Option 1: Set it directly to the hidden field if it exists in the form
        frappe.web_form.set_value('referred_by', referrer);

        // Option 2: Store it globally in the session if you want to be extra safe
        window.current_referrer = referrer;
    }

    setTimeout(() => {
        let parent = document.querySelector('.web-form-body') || 
                     document.querySelector('.form-body') || 
                     document.querySelector('form');

        if (!parent || document.getElementById('manual-custom-questions')) return;

        let custom_section = document.createElement('div');
        custom_section.id = "manual-custom-questions";
        custom_section.className = "web-form-container";

        custom_section.innerHTML = `
            <div class="frappe-control" style="margin-bottom: var(--margin-md);">
                <div class="form-group">
                    <label class="control-label">WhatsApp Group <span class="text-danger">*</span> - <a href="https://chat.whatsapp.com/xyz" target="_blank">Join Here</a></label>
                    <div class="checkbox">
                        <label><input type="checkbox" id="custom_whatsapp"> <span class="label-area">I have joined the group</span></label>
                    </div>
                </div>
            </div>

            <div class="frappe-control" style="margin-bottom: var(--margin-md);">
                <div class="form-group">
                    <label class="control-label">Number of kits <span class="text-danger">*</span></label>
                    <select id="custom_kits" class="form-control">
                        <option value="">-- Select --</option>
                        <option value="5">5</option>
                        <option value="10">10</option>
                        <option value="15">15</option>
                        <option value="20">20</option>
                        <option value="30">30</option>
                        <option value="40">40</option>
                        <option value="50">50</option>
                    </select>
                </div>
            </div>

            <div class="frappe-control" style="margin-bottom: var(--margin-md);">
                <div class="form-group">
                    <label class="control-label">Collection Method <span class="text-danger">*</span></label>
                    <select id="custom_location" class="form-control" onchange="document.getElementById('address_wrapper').style.display = this.value === 'Residential' ? 'block' : 'none'">
                        <option value="MSFT Campus IDC">MSFT Campus IDC</option>
                        <option value="Residential">Home Delivery</option>
                    </select>
                </div>
            </div>

            <div id="address_wrapper" class="frappe-control" style="margin-bottom: var(--margin-md); display: none;">
                <div class="form-group">
                    <label class="control-label">Address <span class="text-danger">*</span></label>
                    <textarea id="custom_address" class="form-control" rows="2"></textarea>
                </div>
            </div>

            <div class="frappe-control" style="margin-bottom: var(--margin-md);">
                <div class="form-group">
                    <label class="control-label">Help us organize?</label>
                    <select id="custom_committee" class="form-control">
                        <option value="Later">Perhaps, next time</option>
                        <option value="Action Lead">Action Lead</option>
                        <option value="Impact Multiplier">Impact Multiplier</option>
                        <option value="Both">Both</option>
                    </select>
                </div>
            </div>

            <div class="frappe-control" style="margin-bottom: var(--margin-md);">
                <div class="form-group">
                    <label class="control-label">Your Ideas/Suggestions</label>
                    <textarea id="custom_ideas" class="form-control" rows="2"></textarea>
                </div>
            </div>
        `;

        parent.append(custom_section);

        // Move native comments to the very bottom
        const comms = document.querySelector('[data-fieldname="comments"]');
        if (comms) comms.parentNode.appendChild(comms);

    }, 200);
};

frappe.web_form.validate = () => {
    const getSelectedText = (id) => {
        const e = document.getElementById(id);
        return e ? e.options[e.selectedIndex].text : "";
    };

    // Ensure the referral is mapped
    if (window.current_referrer) {
        frappe.web_form.doc.referred_by = window.current_referrer;
    }

    const joined = document.getElementById('custom_whatsapp')?.checked;
    const kits = document.getElementById('custom_kits')?.value;
    const kits_text = getSelectedText('custom_kits');
    const loc_id = document.getElementById('custom_location')?.value;
    const loc_text = getSelectedText('custom_location');
    const addr = document.getElementById('custom_address')?.value || "";
    const comm_text = getSelectedText('custom_committee');
    const ideas = document.getElementById('custom_ideas')?.value || "";

    // Mandatory Validations
    if (!joined) { return frappe.msgprint(__('Please join the WhatsApp group.')); }
    if (!kits) { return frappe.msgprint(__('Please select the number of kits.')); }
    if (loc_id === "Residential" && !addr.trim()) { return frappe.msgprint(__('Please provide your address.')); }

    // Map to DocType
    frappe.web_form.doc.temp_address = (loc_id === "Residential") ? addr : "";

    // Map to Child Table
    let details = [
        { "question": "Joined WhatsApp Group", "answer": "Yes" },
        { "question": "Kits to Distribute", "answer": kits_text },
        { "question": "Distribution Location", "answer": loc_text }
    ];

    if (comm_text !== "Perhaps, next time") {
        details.push({ "question": "Organizing Committee Role", "answer": comm_text });
    }
    if (ideas.trim()) {
        details.push({ "question": "Volunteer Ideas/Suggestions", "answer": ideas });
    }

    frappe.web_form.doc.extra_details = details;
    return true;
};
